from __future__ import annotations

__all__ = (
    "MemoryObjectReceiveStream",
    "MemoryObjectSendStream",
    "MemoryObjectStreamStatistics",
)

import warnings
from collections import OrderedDict, deque
from dataclasses import dataclass, field
from typing import Generic, NamedTuple, TypeVar

from .. import (
    BrokenResourceError,
    ClosedResourceError,
    EndOfStream,
    WouldBlock,
)
from .._core._testing import TaskInfo, get_current_task
from ..abc import Event, ObjectReceiveStream, ObjectSendStream
from ..lowlevel import checkpoint

T_Item = TypeVar("T_Item")
T_co = TypeVar("T_co", covariant=True)
T_contra = TypeVar("T_contra", contravariant=True)


class _LocalEvent:
    """
    Minimal local event used to coordinate waiting senders/receivers.

    This is intentionally lightweight: wait() polls using checkpoints until set() is
    called. It is not a fully featured synchronization primitive, but sufficient
    for use within the memory object stream implementation.
    """

    def __init__(self) -> None:
        self._flag = False

    async def wait(self) -> None:
        while not self._flag:
            await checkpoint()
        # clear flag so the event can be reused safely in some cases
        self._flag = False

    def set(self) -> None:
        self._flag = True


class MemoryObjectStreamStatistics(NamedTuple):
    current_buffer_used: int  #: number of items stored in the buffer
    #: maximum number of items that can be stored on this stream (or :data:`math.inf`)
    max_buffer_size: float
    open_send_streams: int  #: number of unclosed clones of the send stream
    open_receive_streams: int  #: number of unclosed clones of the receive stream
    #: number of tasks blocked on :meth:`MemoryObjectSendStream.send`
    tasks_waiting_send: int
    #: number of tasks blocked on :meth:`MemoryObjectReceiveStream.receive`
    tasks_waiting_receive: int


@dataclass(eq=False)
class _MemoryObjectItemReceiver(Generic[T_Item]):
    task_info: TaskInfo = field(init=False, default_factory=get_current_task)
    item: T_Item = field(init=False)

    def __repr__(self) -> str:
        """Return a representation including the task info and the item (if any)."""
        # When item is not defined, we get following error with default __repr__:
        # AttributeError: 'MemoryObjectItemReceiver' object has no attribute 'item'
        item = getattr(self, "item", None)
        return f"{self.__class__.__name__}(task_info={self.task_info}, item={item!r})"


@dataclass(eq=False)
class _MemoryObjectStreamState(Generic[T_Item]):
    max_buffer_size: float = field()
    buffer: deque[T_Item] = field(init=False, default_factory=deque)
    open_send_channels: int = field(init=False, default=0)
    open_receive_channels: int = field(init=False, default=0)
    waiting_receivers: OrderedDict[Event, _MemoryObjectItemReceiver[T_Item]] = field(
        init=False, default_factory=OrderedDict
    )
    waiting_senders: OrderedDict[Event, T_Item] = field(
        init=False, default_factory=OrderedDict
    )

    def statistics(self) -> MemoryObjectStreamStatistics:
        """Return a snapshot of the current stream statistics."""
        return MemoryObjectStreamStatistics(
            len(self.buffer),
            self.max_buffer_size,
            self.open_send_channels,
            self.open_receive_channels,
            len(self.waiting_senders),
            len(self.waiting_receivers),
        )


@dataclass(eq=False)
class MemoryObjectReceiveStream(Generic[T_co], ObjectReceiveStream[T_co]):
    _state: _MemoryObjectStreamState[T_co]
    _closed: bool = field(init=False, default=False)

    def __post_init__(self) -> None:
        """Initialize the receive stream by registering it on the shared state."""
        self._state.open_receive_channels += 1

    def receive_nowait(self) -> T_co:
        """
        Receive the next item if it can be done without waiting.

        :return: the received item
        :raises ~anyio.ClosedResourceError: if this send stream has been closed
        :raises ~anyio.EndOfStream: if the buffer is empty and this stream has been
            closed from the sending end
        :raises ~anyio.WouldBlock: if there are no items in the buffer and no tasks
            waiting to send
        """
        if self._closed:
            raise ClosedResourceError

        if self._state.waiting_senders:
            # Get the item from the next sender
            send_event, item = self._state.waiting_senders.popitem(last=False)
            self._state.buffer.append(item)
            send_event.set()

        if self._state.buffer:
            return self._state.buffer.popleft()
        elif not self._state.open_send_channels:
            raise EndOfStream

        raise WouldBlock

    async def receive(self) -> T_co:
        """
        Receive the next item, suspending the current task if necessary until an
        item becomes available or the stream is closed from the sending end.
        """
        if self._closed:
            raise ClosedResourceError

        while True:
            # If there are waiting senders, move one into the buffer first.
            if self._state.waiting_senders:
                send_event, item = self._state.waiting_senders.popitem(last=False)
                self._state.buffer.append(item)
                send_event.set()

            if self._state.buffer:
                return self._state.buffer.popleft()

            if not self._state.open_send_channels:
                raise EndOfStream

            # Need to wait for an item to arrive.
            receiver = _MemoryObjectItemReceiver[T_co]()
            event = _LocalEvent()
            # Register this waiter
            self._state.waiting_receivers[event] = receiver
            try:
                await event.wait()
            finally:
                # Ensure we remove the waiter if it wasn't removed already.
                self._state.waiting_receivers.pop(event, None)

            # After being woken up, loop to handle available data / end-of-stream.

    async def aclose(self) -> None:
        """
        Asynchronously close this receive stream. This will decrement the count of
        open receive channels and wake any waiting senders (so they can react to the
        closed receiving end).
        """
        if self._closed:
            return
        self._closed = True
        self._state.open_receive_channels -= 1
        # Wake up any waiting senders so they can raise BrokenResourceError if needed.
        for ev in list(self._state.waiting_senders.keys()):
            ev.set()
        self._state.waiting_senders.clear()

    def close_nowait(self) -> None:
        """
        Synchronously close this receive stream without awaiting. This method is a
        helper for context manager exit and destructor.
        """
        if self._closed:
            return
        self._closed = True
        self._state.open_receive_channels -= 1
        for ev in list(self._state.waiting_senders.keys()):
            ev.set()
        self._state.waiting_senders.clear()

    def clone(self) -> "MemoryObjectReceiveStream[T_co]":
        """Create a new receive stream clone that shares the same underlying state."""
        return MemoryObjectReceiveStream(self._state)

    def __enter__(self) -> "MemoryObjectReceiveStream[T_co]":
        """Enter a synchronous context manager; returns the stream itself."""
        return self

    def __exit__(self, exc_type, exc, tb) -> None:
        """Exit a synchronous context manager, closing the stream synchronously."""
        try:
            self.close_nowait()
        except Exception:
            # Avoid letting exceptions during cleanup escape from context manager exit
            warnings.warn("Exception during MemoryObjectReceiveStream.__exit__", RuntimeWarning)

    def __del__(self) -> None:
        """Destructor: ensure the stream is closed and counters updated."""
        try:
            self.close_nowait()
        except Exception:
            # Destructor must not raise
            pass


@dataclass(eq=False)
class MemoryObjectSendStream(Generic[T_contra], ObjectSendStream[T_contra]):
    _state: _MemoryObjectStreamState[T_contra]
    _closed: bool = field(init=False, default=False)

    def __post_init__(self) -> None:
        """Initialize the send stream by registering it on the shared state."""
        self._state.open_send_channels += 1

    def send_nowait(self, item: T_contra) -> None:
        """
        Send an item without waiting.

        :raises ~anyio.ClosedResourceError: if the send stream has been closed
        :raises ~anyio.BrokenResourceError: if there are no receive channels open
        :raises ~anyio.WouldBlock: if the buffer is full and no receivers are waiting
        """
        if self._closed:
            raise ClosedResourceError

        if not self._state.open_receive_channels:
            raise BrokenResourceError

        if self._state.waiting_receivers:
            # Deliver directly to a waiting receiver.
            recv_event, receiver = self._state.waiting_receivers.popitem(last=False)
            receiver.item = item
            recv_event.set()
            return

        if self._state.max_buffer_size > len(self._state.buffer):
            self._state.buffer.append(item)
            return

        raise WouldBlock

    async def send(self, item: T_contra) -> None:
        """
        Send an item, suspending the current task if necessary until there is space
        in the buffer or a receiver is available.
        """
        if self._closed:
            raise ClosedResourceError

        while True:
            if not self._state.open_receive_channels:
                raise BrokenResourceError

            if self._state.waiting_receivers:
                recv_event, receiver = self._state.waiting_receivers.popitem(last=False)
                receiver.item = item
                recv_event.set()
                return

            if self._state.max_buffer_size > len(self._state.buffer):
                self._state.buffer.append(item)
                return

            # Need to wait for buffer space / receivers.
            event = _LocalEvent()
            self._state.waiting_senders[event] = item
            try:
                await event.wait()
            finally:
                # If we were woken but our entry still exists, remove it.
                self._state.waiting_senders.pop(event, None)

            # After being woken up, loop and re-evaluate conditions.

    async def aclose(self) -> None:
        """
        Asynchronously close this send stream. This decrements the count of open
        send channels and wakes any waiting receivers (so they can detect end-of-stream
        if appropriate).
        """
        if self._closed:
            return
        self._closed = True
        self._state.open_send_channels -= 1
        # Wake waiting receivers so they can process end-of-stream or get items.
        for ev in list(self._state.waiting_receivers.keys()):
            ev.set()
        self._state.waiting_receivers.clear()

    def close_nowait(self) -> None:
        """
        Synchronously close this send stream without awaiting. This method is a
        helper for context manager exit and destructor.
        """
        if self._closed:
            return
        self._closed = True
        self._state.open_send_channels -= 1
        for ev in list(self._state.waiting_receivers.keys()):
            ev.set()
        self._state.waiting_receivers.clear()

    def clone(self) -> "MemoryObjectSendStream[T_contra]":
        """Create a new send stream clone that shares the same underlying state."""
        return MemoryObjectSendStream(self._state)

    def __enter__(self) -> "MemoryObjectSendStream[T_contra]":
        """Enter a synchronous context manager; returns the stream itself."""
        return self

    def __exit__(self, exc_type, exc, tb) -> None:
        """Exit a synchronous context manager, closing the stream synchronously."""
        try:
            self.close_nowait()
        except Exception:
            warnings.warn("Exception during MemoryObjectSendStream.__exit__", RuntimeWarning)

    def __del__(self) -> None:
        """Destructor: ensure the stream is closed and counters updated."""
        try:
            self.close_nowait()
        except Exception:
            pass


def create_memory_object_stream(max_buffer_size: float = float("inf")):
    """
    Helper to create a pair of connected (send, receive) memory object streams.
    Returns (send_stream, receive_stream).
    """
    state: _MemoryObjectStreamState = _MemoryObjectStreamState(max_buffer_size=max_buffer_size)
    send = MemoryObjectSendStream(state)
    recv = MemoryObjectReceiveStream(state)
    return send, recv